sql:
SELECT COUNT(DISTINCT d.source_id) 
FROM data_sources d 
JOIN data_files f ON d.source_id = f.data_source_id;

external_knowledge:
- "golden trio" refers to the top three regions;
- "shining the brightest" symbolizes the highest productivity;
- "latest chapter" indicates the most recent year of collected data.

sql:
SELECT user_name, department
FROM users
WHERE user_id IN (SELECT user_id FROM data_annotations);

SELECT DISTINCT ds.source_name 
FROM economic_data ed 
JOIN data_sources ds ON ed.source_id = ds.source_id;

external_knowledge:
- "stars" metaphorically refers to users who have highly rated visualizations; 
- "illuminated the way" refers to giving ratings;
- "brightest beacon" refers to the visualization with the highest rating.

sql:
SELECT analysis_type, result
FROM analysis_results
WHERE result_id = 1;

SELECT AVG(gdp) 
FROM economic_data 
WHERE productivity > 10.0 AND unemployment_rate < 5.0;

SELECT DISTINCT users.user_name
FROM users
JOIN ratings ON users.user_id = ratings.user_id;

SELECT region_name, description, TAN(region_id) AS tan_id
FROM regions
WHERE region_id > 0;
